--
-- Name: calculate_available_stock(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_available_stock(p_item_id integer, p_warehouse_id integer) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
    DECLARE
      v_total_stock NUMERIC;
      v_reserved    NUMERIC;
    BEGIN
      SELECT COALESCE(SUM(quantity_in - quantity_out), 0)
      INTO   v_total_stock
      FROM   stock_ledger
      WHERE  item_id = p_item_id AND warehouse_id = p_warehouse_id;

      SELECT COALESCE(SUM(quantity_remaining), 0)
      INTO   v_reserved
      FROM   inventory_reservations
      WHERE  item_id = p_item_id AND warehouse_id = p_warehouse_id AND status = 'active';

      RETURN GREATEST(0, v_total_stock - v_reserved);
    END;
    $$;


SET default_tablespace = '';

SET default_table_access_method = heap;

