--
-- Name: okr_key_results; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.okr_key_results (
    id integer NOT NULL,
    objective_id integer NOT NULL,
    company_id integer NOT NULL,
    title text NOT NULL,
    description text,
    unit text,
    start_value numeric(15,4) DEFAULT 0,
    target_value numeric(15,4) NOT NULL,
    current_value numeric(15,4) DEFAULT 0,
    progress_pct numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (target_value = start_value) THEN (0)::numeric
    ELSE LEAST((100)::numeric, GREATEST((0)::numeric, (((current_value - start_value) * 100.0) / NULLIF((target_value - start_value), (0)::numeric))))
END) STORED,
    kr_type text DEFAULT 'metric'::text NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    owner_id integer,
    due_date date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT okr_key_results_kr_type_check CHECK ((kr_type = ANY (ARRAY['metric'::text, 'milestone'::text, 'boolean'::text]))),
    CONSTRAINT okr_key_results_status_check CHECK ((status = ANY (ARRAY['active'::text, 'completed'::text, 'at_risk'::text, 'cancelled'::text])))
);


