--
-- Name: v_batch_stock; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_batch_stock AS
 SELECT ib.id,
    ib.item_id,
    ib.warehouse_id,
    ib.batch_number,
    ib.received_date,
    ib.expiry_date,
    ib.supplier_id,
    ib.grn_id,
    ib.quantity_received,
    ib.quantity_available,
    ib.quantity_consumed,
    ib.quantity_reserved,
    ib.rate,
    ib.status,
    ib.deleted_at,
    ib.created_at,
    ib.updated_at,
    ii.item_code,
    ii.item_name,
    ii.unit_of_measure,
    w.warehouse_name,
    (CURRENT_DATE - ib.received_date) AS age_days,
    (ib.quantity_available * ib.rate) AS stock_value,
        CASE
            WHEN (ib.quantity_available <= (0)::numeric) THEN 'depleted'::text
            WHEN ((ib.expiry_date IS NOT NULL) AND (ib.expiry_date <= (CURRENT_DATE + '30 days'::interval))) THEN 'expiring_soon'::text
            ELSE 'active'::text
        END AS stock_status
   FROM ((public.inventory_batches ib
     JOIN public.inventory_items ii ON ((ib.item_id = ii.id)))
     JOIN public.warehouses w ON ((ib.warehouse_id = w.id)))
  WHERE (ib.deleted_at IS NULL);


--
-- Name: v_stock_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_stock_summary AS
 SELECT ii.id,
    ii.item_code,
    ii.item_name,
    ii.item_type,
    ii.unit_of_measure,
    ii.reorder_level,
    w.id AS warehouse_id,
    w.warehouse_name,
    COALESCE(sum((sl.quantity_in - sl.quantity_out)), (0)::numeric) AS balance,
    COALESCE(sum((sl.quantity_in - sl.quantity_out)), (0)::numeric) AS current_stock,
    COALESCE(avg(NULLIF(sl.rate, (0)::numeric)), (0)::numeric) AS avg_rate,
        CASE
            WHEN (COALESCE(sum((sl.quantity_in - sl.quantity_out)), (0)::numeric) <= (0)::numeric) THEN 'out_of_stock'::text
            WHEN (COALESCE(sum((sl.quantity_in - sl.quantity_out)), (0)::numeric) <= ii.reorder_level) THEN 'low_stock'::text
            ELSE 'in_stock'::text
        END AS stock_status
   FROM ((public.inventory_items ii
     CROSS JOIN public.warehouses w)
     LEFT JOIN public.stock_ledger sl ON (((ii.id = sl.item_id) AND (w.id = sl.warehouse_id))))
  WHERE ((ii.deleted_at IS NULL) AND (w.deleted_at IS NULL))
  GROUP BY ii.id, ii.item_code, ii.item_name, ii.item_type, ii.unit_of_measure, ii.reorder_level, w.id, w.warehouse_name;


